\begin{align}
\E[\hat{\beta}]
&= \E[(X^\top X)^{-1} X^\top y]\\
&= \E[(X^\top X)^{-1} X^\top (X\beta + u)]\\
&= \E[(X^\top X)^{-1} X^\top X \beta] + \E[(X^\top X)^{-1} X^\top u]\\
&= \E[\beta] + (X^\top X)^{-1} X^\top \E[u]\\
&= \beta + (X^\top X)^{-1} X^\top \E[u] \quad (\because \beta \text{ は定数のため } E[\beta] = \beta )\\
&= \beta \quad (\because \text{仮定より} E[u] = 0)\\
\end{align}

