\begin{align}
\hat{\beta}_{ML}
&= \argmax_{\beta} \sum^N_{i=1} (y_i - x_i^\top \beta)^2\\
&= (X^\top X)^{-1} X^\top y\\
\\
\hat{\sigma}_{ML}
&= \argmax_{\sigma} \
\left(
  - \frac{N}{2} \ln \sigma^2
  - \frac{1}{2\sigma^2} \sum^N_{i=1} (y_i - x_i^\top \beta)^2
\right)\\
&= \sqrt{ \frac{1}{N} \sum^N_{i=1} (y_i - x_i^\top \hat{\beta}_{ML})^2 }
\end{align}

